// src/components/GroupCards.jsx
import '../styles/GroupCards.css';

export default function GroupCard({ id, name, creator, members = [], onClick }) {
    return (
        <div className="group-card" onClick={onClick}>
            <h2>{name}</h2>
            <p><strong>Créateur :</strong> {creator}</p>
            <p><strong>Membres :</strong> {members.length}</p>
        </div>
    );
}
